// 朴素背包法
void solve(int CASE)
{
	int m, v, n; cin >> m >> v >> n;
	var p = vector<tuple<int, int, int>>(n + 1);
	fa(i, 1, n) {
		int a, b, c; cin >> a >> b >> c;
		p[i] = { a, b, c };
	}

	var dp = Vec3<int>(n + 2, m + 1, v + 1); // 为了回溯方案路径，多开一维
	fb(i, n, 1) { // 为了最小字典序方案，倒序
		const var& [a, b, c] = p[i];
		dp[i] = dp[i + 1];
		fb(j, m, a)fb(k, v, b)
			dp[i][j][k] = max(dp[i][j][k], dp[i][j - a][k - b] + c);
	}
	cout << dp[1][m][v] << endl;

	// 正序枚举，看看 i 是否为必须
	int na = m, nb = v, nc = dp[1][m][v];
	fa(i, 1, n) {
		const var& [a, b, c] = p[i];
		if (na >= a and nb >= b and dp[i + 1][na - a][nb - b] + c == nc) {
			cout << i << ' ';
			na -= a, nb -= b, nc -= c;
		}
	}
	cout << endl;
	return;
}

// bool 数组记录，省内存
// vis：在 j，k 容量的情况下，为了拿最大，是否应该装第 i 个物品
void solve(int CASE)
{
	int m, v, n; cin >> m >> v >> n;
	var p = vector<tuple<int, int, int>>(n + 1);
	fa(i, 1, n) {
		int a, b, c; cin >> a >> b >> c;
		p[i] = { a, b, c };
	}

	var dp = Vec2<int>(m + 1, v + 1); // 滚动背包
	var vis = Vec3<bool>(n + 2, m + 1, v + 1); // 在 j，k 容量的情况下，为了拿最大，是否应该使用第 i 个物品
	fb(i, n, 1) { // 为了最小字典序方案，倒序
		const var& [a, b, c] = p[i];
		fb(j, m, a)fb(k, v, b) {
			if (dp[j][k] <= dp[j - a][k - b] + c) // 取等号，是因为要取最小下标
				vis[i][j][k] = 1;
			dp[j][k] = max(dp[j][k], dp[j - a][k - b] + c);
		}
	}
	cout << dp[m][v] << endl;

	// 正序枚举，看看 i 是否为必须
	int na = m, nb = v;
	fa(i, 1, n) {
		const var& [a, b, c] = p[i];
		if (vis[i][na][nb]) {
			cout << i << ' ';
			na -= a, nb -= b;
		}
	}
	cout << endl;
}
